import graphene
import psycopg2
from psycopg2.extras import RealDictCursor
from typing import List, Optional
import re

class SearchResult(graphene.ObjectType):
    id = graphene.Int()
    name = graphene.String()
    description = graphene.String()
    category = graphene.String()
    created_at = graphene.DateTime()

class SearchQuery(graphene.ObjectType):
    search = graphene.List(
        SearchResult,
        query=graphene.String(required=True),
        category=graphene.String(),
        limit=graphene.Int(default_value=100),
        offset=graphene.Int(default_value=0)
    )

    def resolve_search(self, info, query: str, category: Optional[str] = None, limit: int = 100, offset: int = 0):
        # Validate and sanitize inputs
        if not query or len(query.strip()) < 1:
            return []
        
        # Limit parameters to prevent abuse
        limit = min(limit, 1000)  # Max 1000 results
        offset = max(0, offset)
        
        # Sanitize query input - remove potentially dangerous characters
        query = re.sub(r'[;\'"\\]', '', query)
        
        # Build dynamic SQL with parameterized queries
        sql_parts = []
        params = []
        
        # Add search terms to WHERE clause
        search_terms = query.split()
        for i, term in enumerate(search_terms):
            if i == 0:
                sql_parts.append("(name ILIKE %s OR description ILIKE %s OR category ILIKE %s)")
            else:
                sql_parts.append("AND (name ILIKE %s OR description ILIKE %s OR category ILIKE %s)")
            params.extend([f"%{term}%", f"%{term}%", f"%{term}%"])
        
        where_clause = " ".join(sql_parts)
        
        # Add category filter if provided
        if category:
            where_clause += " AND category = %s"
            params.append(category)
        
        # Build final query
        sql = f"""
            SELECT id, name, description, category, created_at 
            FROM products 
            WHERE {where_clause}
            ORDER BY created_at DESC
            LIMIT %s OFFSET %s
        """
        
        params.extend([limit, offset])
        
        try:
            # Use connection from pool or create new one
            conn = psycopg2.connect(
                host="localhost",
                database="mydb",
                user="user",
                password="password"
            )
            cursor = conn.cursor(cursor_factory=RealDictCursor)
            cursor.execute(sql, params)
            results = cursor.fetchall()
            cursor.close()
            conn.close()
            
            return [SearchResult(**row) for row in results]
        except Exception as e:
            # Log error securely (don't expose to client)
            print(f"Search error: {str(e)}")
            return []

class Query(SearchQuery, graphene.ObjectType):
    pass

schema = graphene.Schema(query=Query)